mapper.select:
SELECT
,yonghu.yonghu_name as yonghuName ,yonghu.yonghu_photo as yonghuPhoto ,shangjia.shangjia_name as shangjiaName ,shangjia.shangjia_phone as shangjiaPhone FROM shangjia_chat a LEFT JOIN yonghu yonghu ON a.yonghu_id = yonghu.id LEFT JOIN shangjia shangjia ON a.shangjia_id = shangjia.id
and a.id in
#{item}
and a.yonghu_id = #{params.yonghuId}
and a.shangjia_id = #{params.shangjiaId}
and a.shangjia_chat_issue_text like CONCAT('%',#{params.shangjiaChatIssueText},'%')
and a.shangjia_chat_reply_text like CONCAT('%',#{params.shangjiaChatReplyText},'%')
and a.zhuangtai_types = #{params.zhuangtaiTypes}
and UNIX_TIMESTAMP(a.issue_time) >= UNIX_TIMESTAMP(#{params.issueTimeStart})
and UNIX_TIMESTAMP(a.issue_time) <= UNIX_TIMESTAMP(#{params.issueTimeEnd})
and UNIX_TIMESTAMP(a.reply_time) >= UNIX_TIMESTAMP(#{params.replyTimeStart})
and UNIX_TIMESTAMP(a.reply_time) <= UNIX_TIMESTAMP(#{params.replyTimeEnd})
and yonghu.yonghu_name like CONCAT('%',#{params.yonghuName},'%')
and shangjia.shangjia_name like CONCAT('%',#{params.shangjiaName},'%')
order by a.${params.sort} ${params.order}
